import{_ as a,o as t,c as p,j as r,a as d,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"诺顿的强化机","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/8.物品改造/诺顿的强化机.md","filePath":"4.资源分区/7.物品与装备/8.物品改造/诺顿的强化机.md"}'),n={name:"4.资源分区/7.物品与装备/8.物品改造/诺顿的强化机.md"};function o(b,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"诺顿的强化机",tabindex:"-1"},[d("诺顿的强化机 "),r("a",{class:"header-anchor",href:"#诺顿的强化机","aria-label":'Permalink to "诺顿的强化机"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),s('<h1 id="诺顿的强化机-1" tabindex="-1">诺顿的强化机 <a class="header-anchor" href="#诺顿的强化机-1" aria-label="Permalink to &quot;诺顿的强化机&quot;">​</a></h1><p>诺顿的强化机</p><p>“想看看你的装备都是由什么样的晶体组成的吗，诺顿牌强化机，实现你的愿望。”</p><p>这是一个体积8的金属机器，机身上有一红一蓝两个巨大的灯泡，从机器的顶端有一个直径约40公分的圆形孔洞，可以将武器从中放入，如果是一些体积较大的武器没法放入，也可以拆解部分机器的保护罩，如果是大型载具之类的物品，还可以拆解后依次投入。<br> 在孔洞中，可以看到匀速旋转的巨大齿轮，足够将一切投入其中的物体搅碎（bushi），但是千万不要把活体等东西投入，也不要将其作为谋害人的工具，主神会一直盯着你，任何邪恶，终将绳之以法！！！</p><p>将武器放入之后，同时支付列表中的点数，机器会进入约十分钟的运行状态，红蓝灯光会交替闪烁，如果最后亮起的是红灯，则视为强化成功，武器将会获得强化，获得对应的攻击检定上的器械加值、附加成功等效果，如果失败，则武器会被破坏，生成大量无色小晶体……<br> 才怪，失败后会返还部分奖励点并降低一级强化等级。</p><p>武器的强化需要按等级进行，每级带来的额外效果为可以叠加，但每级别获得的DP与附加成功为替代关系。强化失败后强化等级会降低一级（至多降低至1级）。<br> 额外效果只有在持有此武器时才可以生效。<br> 该强化机可以用于强化防具，此时提供的dp会替换为增加护甲防御及护甲防御附加。<br> 该强化机可以用于强化载具，强化载具的防御、武器需要分别进行。<br> 该强化机可以用于强化护符，此时提供的dp会替换为增加意志豁免及意志豁免附加。<br> 该强化机可以用于强化戒指，此时提供的dp会替换为增加强韧豁免及强韧豁免附加。<br> 该强化机可以用于强化手镯，此时提供的dp会替换为增加反射豁免及反射豁免附加。</p><p>强化投掷方法，投掷rd【投入奖励点】，如果出数小于等于【失败返还】值，则视为强化成功，反之则失败。</p><p>强化名称 投入奖励点 失败返还  dp 附加 额外效果<br> 破旧 1000  750  1 1 增加10点声望<br> 平凡 1000  750  2 2 增加5点先攻<br> 精品 1000  500  3 3 选择一种能量池增加10点上限<br> 稀有 1000  500  4 4 武器伤害/法术强度增加3<br> 高级 1000  500  5 5 武器攻击距离增加5米<br> 传说 1000  250  6 6 3点严重伤害转为韧性<br> 史诗 1000  250  7 7 6点严重伤害转为韧性<br> 神话 1000  250  8 8 武器伤害/法术强度增加10</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(n,[["render",o]]);export{f as __pageData,m as default};
